#ifndef LWIP_GETH_CC_H
#define LWIP_GETH_CC_H

#define LWIP_NO_STDINT_H 1

#include <Cpu/Std/Ifx_Types.h>
#include "lwipopts.h"
#include <stdio.h>

typedef uint8  u8_t;
typedef uint16 u16_t;
typedef uint32 u32_t;
typedef sint8  s8_t;
typedef sint16 s16_t;
typedef sint32 s32_t;

typedef u32_t  mem_ptr_t;

/* printf formatters for data types */
#define U16_F              "u"
#define S16_F              "d"
#define X16_F              "x"
#define U32_F              "lu"
#define S32_F              "lu"
#define X32_F              "lu"
#define SZT_F              "zu"

#define BYTE_ORDER         LITTLE_ENDIAN

#if defined(__GNUC__) || defined(__DCC__)
#define PACK_STRUCT_BEGIN
#define PACK_STRUCT_STRUCT __attribute__ ((__packed__))
#define PACK_STRUCT_END
#define PACK_STRUCT_FIELD(x) x
#elif defined(__TASKING__) || defined(__ghs__)
#define LWIP_SKIP_PACKING_CHECK 1
#define PACK_STRUCT_BEGIN
#define PACK_STRUCT_STRUCT
#define PACK_STRUCT_END
#define PACK_STRUCT_FIELD(x) x
#endif

#define LWIP_PROVIDE_ERRNO

#define abort(void)

#ifdef LWIP_DEBUG
#define LWIP_PLATFORM_ASSERT(msg)                                                \
  printf("Assertion \"%s\" failed at line %d in %s\n", msg, __LINE__, __FILE__); \
  abort()
#define LWIP_PLATFORM_DIAG(msg)   printf msg; printf("\r\n");
#else
#define LWIP_PLATFORM_ASSERT(msg) ((void)0)
#define LWIP_PLATFORM_DIAG(msg)   ((void)0)

#endif

#endif  //__LWIP_EE_CC_TRICORE_H__
